    session_set(cache, id1, "ip_address", "192.168.1.100");

    session_set(cache, id2, "username", "bob");
    session_set(cache, id2, "role", "user");
    session_set(cache, id2, "cart_items", "3");

    session_set(cache, id3, "username", "charlie");
    session_set(cache, id3, "role", "moderator");

    /* Access session data */
    printf("\n--- Accessing Session Data ---\n");
