    if (reinit) {
        printf("Session 3 re-initialized successfully!\n");
        session_set(cache, id3, "username", "charlie_reloaded");
        session_set(cache, id3, "role", "supermod");
        session_print(cache, id3);
    }

    /* Remove a specific key */
    printf("--- Removing key 'role' from Session 1 ---\n");
    session_remove_key(cache, id1, "role");
    session_print(cache, id1);

    /* Wait for Session 1 to expire (5-second TTL) */
    printf("--- Waiting for Session 1 to expire (5 seconds) ---\n");
    printf("Sleeping...\n");

    /* Simulate time passing - in production this happens naturally */
    #ifdef _WIN32
    Sleep(6000);
    #else
    {
        struct timespec ts = {6, 0};
        nanosleep(&ts, NULL);
    }
    #endif

    /* Try to access expired session */
    val = session_get(cache, id1, "username");
    printf("Session 1 username after expiry: %s\n", val ? val : "(expired/null)");
    printf("Session 1 state: %d\n", session_get_state(cache, id1));
    printf("Session 1 ID still cached: %s\n",
           session_id_cached(cache, id1) ? "YES" : "NO");

    /* Re-initialize expired session */
    printf("\n--- Re-initializing expired Session 1 ---\n");
    reinit = session_reinitialize(cache, id1, 3600);
